package org.apache.flink.streaming.api.windowing.triggers;

import org.apache.flink.annotation.PublicEvolving;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;

/**
 * A {@link Trigger} that fires once the watermark passes the end of a pricing session window (market
 * close time).
 *
 * <p>This trigger is designed for financial trading data and fires at configurable market close
 * times. It registers an event-time timer at the market close timestamp and fires when the watermark
 * reaches that time.
 *
 * <p>The trigger also supports early firing for special market events (e.g., circuit breaker halts)
 * by allowing custom firing logic via subclassing.
 *
 * @see org.apache.flink.streaming.api.watermark.Watermark
 */
@PublicEvolving
public class PricingSessionTrigger extends Trigger<Object, TimeWindow> {
    private static final long serialVersionUID = 1L;

    private PricingSessionTrigger() {}

    @Override
    public TriggerResult onElement(
            Object element, long timestamp, TimeWindow window, TriggerContext ctx)
            throws Exception {
        // Register an event-time timer for the market close (window end)
        long windowEnd = window.maxTimestamp();
        if (windowEnd <= ctx.getCurrentWatermark()) {
            // If watermark is already past the window end, fire immediately
            return TriggerResult.FIRE;
        } else {
            // Register a timer for when watermark reaches window end
            ctx.registerEventTimeTimer(windowEnd);
            return TriggerResult.CONTINUE;
        }
    }

    @Override
    public TriggerResult onEventTime(long time, TimeWindow window, TriggerContext ctx) {
        // Fire when event time reaches market close
        return time == window.maxTimestamp() ? TriggerResult.FIRE : TriggerResult.CONTINUE;
    }

    @Override
    public TriggerResult onProcessingTime(long time, TimeWindow window, TriggerContext ctx)
            throws Exception {
        // Do not fire on processing time for trading sessions
        return TriggerResult.CONTINUE;
    }

    @Override
    public void clear(TimeWindow window, TriggerContext ctx) throws Exception {
        // Clean up the event-time timer registered for this window
        ctx.deleteEventTimeTimer(window.maxTimestamp());
    }

    @Override
    public boolean canMerge() {
        // This trigger supports merging of windows
        return true;
    }

    @Override
    public void onMerge(TimeWindow window, OnMergeContext ctx) {
        // Re-register the timer for the merged window if watermark hasn't passed the end yet
        long windowMaxTimestamp = window.maxTimestamp();
        if (windowMaxTimestamp > ctx.getCurrentWatermark()) {
            ctx.registerEventTimeTimer(windowMaxTimestamp);
        }
    }

    @Override
    public String toString() {
        return "PricingSessionTrigger()";
    }

    /**
     * Creates a new {@code PricingSessionTrigger} that fires when the watermark passes the market
     * close time.
     *
     * @return A new PricingSessionTrigger instance.
     */
    public static PricingSessionTrigger create() {
        return new PricingSessionTrigger();
    }
}

