package org.apache.flink.streaming.api.windowing.assigners;

import org.apache.flink.annotation.PublicEvolving;
import org.apache.flink.api.common.ExecutionConfig;
import org.apache.flink.api.common.typeutils.TypeSerializer;
import org.apache.flink.streaming.api.windowing.triggers.PricingSessionTrigger;
import org.apache.flink.streaming.api.windowing.triggers.Trigger;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;

import java.time.Instant;
import java.time.LocalDate;
import java.time.LocalDateTime;
import java.time.LocalTime;
import java.time.ZoneId;
import java.time.ZonedDateTime;
import java.util.Collection;
import java.util.Collections;

/**
 * A {@link WindowAssigner} that windows financial trading events into trading sessions based on
 * market hours (e.g., NYSE 09:30-16:00 ET, LSE 08:00-16:30 GMT).
 *
 * <p>Unlike fixed time windows, pricing session windows align with actual trading session
 * boundaries, which is essential for financial analytics. The assigner groups events by trading
 * session rather than fixed intervals.
 *
 * <p>This assigner supports:
 * <ul>
 *   <li>Multiple markets with different trading hours
 *   <li>Overnight sessions (e.g., futures markets trading across midnight)
 *   <li>Timezone-aware session boundary calculation
 *   <li>Window merging for overlapping sessions
 * </ul>
 *
 * <p>Example usage:
 * <pre>{@code
 * DataStream<TradingEvent> events = ...;
 * KeyedStream<TradingEvent, String> keyed = events.keyBy(e -> e.getMarketId());
 * WindowedStream<TradingEvent, String, TimeWindow> windowed = keyed.window(
 *   PricingSessionWindow.forMarket(
 *     "NYSE",
 *     ZoneId.of("America/New_York"),
 *     LocalTime.of(9, 30),
 *     LocalTime.of(16, 0)
 *   )
 * );
 * }</pre>
 */
@PublicEvolving
public class PricingSessionWindow extends MergingWindowAssigner<Object, TimeWindow> {
    private static final long serialVersionUID = 1L;

    private final String marketId;
    private final ZoneId timezone;
    private final LocalTime sessionOpen;
    private final LocalTime sessionClose;

    /**
     * Creates a new PricingSessionWindow assigner for a specific market.
     *
     * @param marketId The unique identifier for the market (e.g., "NYSE", "LSE").
     * @param timezone The timezone in which the session times are specified.
     * @param sessionOpen The opening time of the trading session (in the specified timezone).
     * @param sessionClose The closing time of the trading session (in the specified timezone).
     */
    private PricingSessionWindow(
            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
        if (marketId == null || marketId.isEmpty()) {
            throw new IllegalArgumentException("Market ID cannot be null or empty");
        }
        if (timezone == null) {
            throw new IllegalArgumentException("Timezone cannot be null");
        }
        if (sessionOpen == null || sessionClose == null) {
            throw new IllegalArgumentException("Session times cannot be null");
        }

        this.marketId = marketId;
        this.timezone = timezone;
        this.sessionOpen = sessionOpen;
        this.sessionClose = sessionClose;
    }

    @Override
    public Collection<TimeWindow> assignWindows(
            Object element, long timestamp, WindowAssignerContext context) {
        // Convert timestamp to the market's timezone
        ZonedDateTime zonedDateTime = Instant.ofEpochMilli(timestamp).atZone(timezone);
        LocalDateTime localDateTime = zonedDateTime.toLocalDateTime();
        LocalTime timeOfDay = localDateTime.toLocalTime();
        LocalDate date = localDateTime.toLocalDate();

        // Determine which session this timestamp belongs to
        LocalDateTime sessionStartDateTime;
        LocalDateTime sessionEndDateTime;

        if (isOvernightSession()) {
            // For overnight sessions (e.g., close >= open), e.g. 18:00 to 09:00 next day
            if (timeOfDay.isBefore(sessionClose)) {
                // We're in the early morning part of an overnight session
                // Session started yesterday
                sessionStartDateTime = LocalDateTime.of(date.minusDays(1), sessionOpen);
                sessionEndDateTime = LocalDateTime.of(date, sessionClose);
            } else if (timeOfDay.isBefore(sessionOpen) || timeOfDay.equals(sessionOpen)) {
                // Before session open on the same day - not in a session
                // Return a window for the previous session that ended
                sessionStartDateTime = LocalDateTime.of(date.minusDays(1), sessionOpen);
                sessionEndDateTime = LocalDateTime.of(date, sessionClose);
            } else {
                // We're in the main trading period of an overnight session
                sessionStartDateTime = LocalDateTime.of(date, sessionOpen);
                sessionEndDateTime = LocalDateTime.of(date.plusDays(1), sessionClose);
            }
        } else {
            // For regular sessions (e.g., open < close like 09:30 to 16:00)
            if (timeOfDay.isBefore(sessionOpen)) {
                // Before session opens - use yesterday's session
                sessionStartDateTime = LocalDateTime.of(date.minusDays(1), sessionOpen);
                sessionEndDateTime = LocalDateTime.of(date.minusDays(1), sessionClose);
            } else if (timeOfDay.isBefore(sessionClose) || timeOfDay.equals(sessionOpen)) {
                // During session
                sessionStartDateTime = LocalDateTime.of(date, sessionOpen);
                sessionEndDateTime = LocalDateTime.of(date, sessionClose);
            } else {
                // After session close - use today's session
                sessionStartDateTime = LocalDateTime.of(date, sessionOpen);
                sessionEndDateTime = LocalDateTime.of(date, sessionClose);
            }
        }

        // Convert back to UTC milliseconds
        long sessionStartMillis = sessionStartDateTime.atZone(timezone).toInstant().toEpochMilli();
        long sessionEndMillis = sessionEndDateTime.atZone(timezone).toInstant().toEpochMilli();

        return Collections.singletonList(new TimeWindow(sessionStartMillis, sessionEndMillis));
    }

    @Override
    public Trigger<Object, TimeWindow> getDefaultTrigger() {
        return PricingSessionTrigger.create();
    }

    @Override
    public TypeSerializer<TimeWindow> getWindowSerializer(ExecutionConfig executionConfig) {
        return new TimeWindow.Serializer();
    }

    @Override
    public boolean isEventTime() {
        return true;
    }

    @Override
    public void mergeWindows(
            Collection<TimeWindow> windows, MergingWindowAssigner.MergeCallback<TimeWindow> c) {
        // Delegate to TimeWindow's standard merging logic for overlapping windows
        TimeWindow.mergeWindows(windows, c);
    }

    @Override
    public String toString() {
        return "PricingSessionWindow{"
                + "marketId='"
                + marketId
                + '\''
                + ", timezone="
                + timezone
                + ", sessionOpen="
                + sessionOpen
                + ", sessionClose="
                + sessionClose
                + '}';
    }

    /**
     * Checks if this is an overnight session (session spans across midnight).
     *
     * @return true if sessionClose is before sessionOpen (overnight session), false otherwise.
     */
    private boolean isOvernightSession() {
        return sessionClose.isBefore(sessionOpen);
    }

    /**
     * Factory method to create a new PricingSessionWindow assigner for a specific market.
     *
     * @param marketId The unique identifier for the market (e.g., "NYSE", "LSE", "CME").
     * @param timezone The timezone in which the session times are defined.
     * @param open The market opening time.
     * @param close The market closing time.
     * @return A new PricingSessionWindow instance configured for the specified market.
     */
    public static PricingSessionWindow forMarket(
            String marketId, ZoneId timezone, LocalTime open, LocalTime close) {
        return new PricingSessionWindow(marketId, timezone, open, close);
    }
}
